import React, { useState } from 'react';
import { Sparkles, Zap } from 'lucide-react';

const OnboardingModal: React.FC<{ show: boolean; onClose: () => void; onNavigate: (view: string) => void }> = ({ show, onClose, onNavigate }) => {
  const [onboardingStep, setOnboardingStep] = useState(0);

  if (!show) return null;

  const handleSkip = () => {
    localStorage.setItem('citedby_onboarded', 'true');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center bg-black/70 backdrop-blur-sm">
      <div className="relative w-full max-w-[480px] mx-4 bg-[#13131d] border border-white/[0.08] rounded-2xl shadow-2xl shadow-black/60 overflow-hidden">
        {/* Skip button */}
        <button
          onClick={handleSkip}
          className="absolute top-4 right-4 text-gray-500 hover:text-gray-300 transition-colors text-sm z-10"
        >
          Passer
        </button>

        {/* Step 1 - Welcome */}
        {onboardingStep === 0 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-500 to-violet-600 flex items-center justify-center mb-6 shadow-lg shadow-purple-900/40">
              <Sparkles size={36} className="text-white" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-3">Bienvenue sur CitedBy.ai !</h2>
            <p className="text-gray-400 text-[15px] leading-relaxed mb-8">
              Vous disposez de <span className="text-purple-400 font-semibold">50 crédits offerts</span> pour découvrir la plateforme d'optimisation AEO la plus avancée.
            </p>
            <button
              onClick={() => setOnboardingStep(1)}
              className="w-full py-3 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white font-semibold rounded-xl transition-all duration-200 shadow-lg shadow-purple-900/30"
            >
              Découvrir →
            </button>
          </div>
        )}

        {/* Step 2 - Key Features */}
        {onboardingStep === 1 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold text-white mb-2">Vos outils clés</h2>
            <p className="text-gray-500 text-sm mb-6">Tout ce dont vous avez besoin pour dominer l'AEO</p>
            <div className="w-full flex flex-col gap-3 mb-8">
              <div className="flex items-start gap-4 p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] text-left">
                <span className="text-2xl mt-0.5">🔍</span>
                <div>
                  <h3 className="text-white font-semibold text-[15px] mb-1">Audit AEO Instantané</h3>
                  <p className="text-gray-500 text-[13px] leading-relaxed">Analysez votre visibilité sur ChatGPT, Claude et Gemini</p>
                </div>
              </div>
              <div className="flex items-start gap-4 p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] text-left">
                <span className="text-2xl mt-0.5">✨</span>
                <div>
                  <h3 className="text-white font-semibold text-[15px] mb-1">Outils Génératifs</h3>
                  <p className="text-gray-500 text-[13px] leading-relaxed">8 outils IA pour optimiser votre contenu</p>
                </div>
              </div>
              <div className="flex items-start gap-4 p-4 rounded-xl bg-white/[0.03] border border-white/[0.06] text-left">
                <span className="text-2xl mt-0.5">📊</span>
                <div>
                  <h3 className="text-white font-semibold text-[15px] mb-1">Dashboard Pro</h3>
                  <p className="text-gray-500 text-[13px] leading-relaxed">Suivez vos scores et citations en temps réel</p>
                </div>
              </div>
            </div>
            <button
              onClick={() => setOnboardingStep(2)}
              className="w-full py-3 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white font-semibold rounded-xl transition-all duration-200 shadow-lg shadow-purple-900/30"
            >
              Continuer →
            </button>
          </div>
        )}

        {/* Step 3 - Ready to Start */}
        {onboardingStep === 2 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/30 flex items-center justify-center mb-6">
              <Zap size={36} className="text-purple-400" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-3">Prêt à commencer ?</h2>
            <p className="text-gray-400 text-[15px] leading-relaxed mb-8">
              Lancez votre premier audit ou explorez le dashboard pour découvrir toutes les fonctionnalités.
            </p>
            <button
              onClick={() => {
                localStorage.setItem('citedby_onboarded', 'true');
                onClose();
                onNavigate('analyze');
              }}
              className="w-full py-3 bg-gradient-to-r from-purple-600 to-violet-600 hover:from-purple-500 hover:to-violet-500 text-white font-semibold rounded-xl transition-all duration-200 shadow-lg shadow-purple-900/30 mb-3"
            >
              Lancer mon premier audit
            </button>
            <button
              onClick={() => {
                localStorage.setItem('citedby_onboarded', 'true');
                onClose();
                onNavigate('dashboard');
              }}
              className="w-full py-3 bg-white/[0.05] hover:bg-white/[0.08] text-gray-300 hover:text-white font-medium rounded-xl transition-all duration-200 border border-white/[0.06]"
            >
              Explorer le dashboard
            </button>
          </div>
        )}

        {/* Step dots */}
        <div className="flex items-center justify-center gap-2 pb-6">
          {[0, 1, 2].map((step) => (
            <div
              key={step}
              className={`w-2 h-2 rounded-full transition-all duration-300 ${
                onboardingStep === step
                  ? 'bg-purple-500 w-6'
                  : 'bg-white/[0.15]'
              }`}
            />
          ))}
        </div>
      </div>
    </div>
  );
};

export default OnboardingModal;
